var greatestLetter = function(s) {
    const present = new Set(s);
    for (let code = 90; code >= 65; code--) {
        const up = String.fromCharCode(code);
        const low = up.toLowerCase();
        if (present.has(up) && present.has(low)) return up;
    }
    return '';
};
